const codes = {"Java": "<span class=\"kw\">abstract class</span> <span class=\"cl\">Handler</span> {\n  <span class=\"kw\">protected</span> <span class=\"cl\">Handler</span> <span class=\"dc\">next</span>;\n\n  <span class=\"cl\">Handler</span> <span class=\"fn\">setNext</span>(<span class=\"cl\">Handler</span> <span class=\"dc\">h</span>) {\n    <span class=\"dc\">next</span> = <span class=\"dc\">h</span>; <span class=\"kw\">return</span> <span class=\"dc\">h</span>;\n  }\n  <span class=\"kw\">abstract boolean</span> <span class=\"fn\">handle</span>(<span class=\"cl\">String</span> <span class=\"dc\">req</span>);\n  <span class=\"kw\">protected boolean</span> <span class=\"fn\">pass</span>(<span class=\"cl\">String</span> <span class=\"dc\">r</span>) {\n    <span class=\"kw\">return</span> <span class=\"dc\">next</span> != <span class=\"kw\">null</span> && <span class=\"dc\">next</span>.<span class=\"fn\">handle</span>(<span class=\"dc\">r</span>);\n  }\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">AuthHandler</span> <span class=\"kw\">extends</span> <span class=\"cl\">Handler</span> {\n  <span class=\"kw\">public boolean</span> <span class=\"fn\">handle</span>(<span class=\"cl\">String</span> <span class=\"dc\">req</span>) {\n    <span class=\"kw\">if</span> (<span class=\"dc\">req</span>.<span class=\"fn\">startsWith</span>(<span class=\"st\">\"Bearer \"</span>) )\n      <span class=\"kw\">return</span> <span class=\"fn\">pass</span>(<span class=\"dc\">req</span>);\n    <span class=\"cl\">System</span>.out.<span class=\"fn\">println</span>(<span class=\"st\">\"401 Unauthorized\"</span>);\n    <span class=\"kw\">return false</span>;\n  }\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">RateLimitHandler</span> <span class=\"kw\">extends</span> <span class=\"cl\">Handler</span> {\n  <span class=\"kw\">public boolean</span> <span class=\"fn\">handle</span>(<span class=\"cl\">String</span> <span class=\"dc\">req</span>) {\n    <span class=\"cm\">// verifica rate limit...</span>\n    <span class=\"kw\">return</span> <span class=\"fn\">pass</span>(<span class=\"dc\">req</span>);\n  }\n}", "CSharp": "<span class=\"kw\">public abstract class</span> <span class=\"cl\">Handler</span> {\n  <span class=\"kw\">protected</span> <span class=\"cl\">Handler</span>? <span class=\"dc\">Next</span>;\n\n  <span class=\"kw\">public</span> <span class=\"cl\">Handler</span> <span class=\"fn\">SetNext</span>(<span class=\"cl\">Handler</span> <span class=\"dc\">h</span>) {\n    <span class=\"dc\">Next</span> = <span class=\"dc\">h</span>; <span class=\"kw\">return</span> <span class=\"dc\">h</span>;\n  }\n  <span class=\"kw\">public abstract bool</span> <span class=\"fn\">Handle</span>(<span class=\"kw\">string</span> <span class=\"dc\">req</span>);\n  <span class=\"kw\">protected bool</span> <span class=\"fn\">Pass</span>(<span class=\"kw\">string</span> <span class=\"dc\">r</span>) =&gt;\n    <span class=\"dc\">Next</span>?.<span class=\"fn\">Handle</span>(<span class=\"dc\">r</span>) ?? <span class=\"kw\">true</span>;\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">AuthHandler</span> : <span class=\"cl\">Handler</span> {\n  <span class=\"kw\">public override bool</span> <span class=\"fn\">Handle</span>(<span class=\"kw\">string</span> <span class=\"dc\">req</span>) =&gt;\n    <span class=\"dc\">req</span>.<span class=\"fn\">StartsWith</span>(<span class=\"st\">\"Bearer \"</span>) && <span class=\"fn\">Pass</span>(<span class=\"dc\">req</span>);\n}", "Python": "<span class=\"kw\">class</span> <span class=\"cl\">Handler</span>:\n  <span class=\"dc\">_next</span> = <span class=\"kw\">None</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">set_next</span>(<span class=\"dc\">self</span>, <span class=\"dc\">h</span>):\n    <span class=\"dc\">self._next</span> = <span class=\"dc\">h</span>; <span class=\"kw\">return</span> <span class=\"dc\">h</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">handle</span>(<span class=\"dc\">self</span>, <span class=\"dc\">req</span>):\n    <span class=\"kw\">raise</span> <span class=\"cl\">NotImplementedError</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">_pass</span>(<span class=\"dc\">self</span>, <span class=\"dc\">r</span>):\n    <span class=\"kw\">return</span> <span class=\"dc\">self._next</span>.<span class=\"fn\">handle</span>(<span class=\"dc\">r</span>) <span class=\"kw\">if</span> <span class=\"dc\">self._next</span> <span class=\"kw\">else</span> <span class=\"kw\">True</span>\n\n\n<span class=\"kw\">class</span> <span class=\"cl\">AuthHandler</span>(<span class=\"cl\">Handler</span>):\n  <span class=\"kw\">def</span> <span class=\"fn\">handle</span>(<span class=\"dc\">self</span>, <span class=\"dc\">req</span>):\n    <span class=\"kw\">if</span> <span class=\"dc\">req</span>.<span class=\"fn\">get</span>(<span class=\"st\">\"token\"</span>):\n      <span class=\"kw\">return</span> <span class=\"dc\">self</span>.<span class=\"fn\">_pass</span>(<span class=\"dc\">req</span>)\n    <span class=\"fn\">print</span>(<span class=\"st\">\"401 Unauthorized\"</span>); <span class=\"kw\">return</span> <span class=\"kw\">False</span>", "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">Handler</span>\n  <span class=\"dc\">attr_writer</span> <span class=\"st\">:next_h</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">handle</span>(<span class=\"dc\">r</span>) = <span class=\"kw\">raise</span> <span class=\"cl\">NotImplementedError</span>\n\n  <span class=\"kw\">protected</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">pass_on</span>(<span class=\"dc\">r</span>) = <span class=\"dc\">@next_h</span>?.<span class=\"fn\">handle</span>(<span class=\"dc\">r</span>) ?? <span class=\"kw\">true</span>\n<span class=\"kw\">end</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">AuthHandler</span> &lt; <span class=\"cl\">Handler</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">handle</span>(<span class=\"dc\">r</span>)\n    <span class=\"dc\">r</span>[<span class=\"st\">:token</span>] ? <span class=\"fn\">pass_on</span>(<span class=\"dc\">r</span>) : <span class=\"kw\">false</span>\n  <span class=\"kw\">end</span>\n<span class=\"kw\">end</span>"}

